from collections import defaultdict

class Solution:
    def maxSum(self, nums, m, k):
        freq = defaultdict(int)
        distinct = 0
        window_sum = 0
        best = 0
        for i, x in enumerate(nums):
            freq[x] += 1
            if freq[x] == 1:
                distinct += 1
            window_sum += x
            if i >= k:
                y = nums[i - k]
                window_sum -= y
                freq[y] -= 1
                if freq[y] == 0:
                    distinct -= 1
            if i >= k - 1 and distinct >= m:
                best = max(best, window_sum)
        return best

