var maxSum = function(nums, m, k) {
    const freq = new Map();
    let distinct = 0;
    let windowSum = 0;
    let best = 0;
    for (let i = 0; i < nums.length; i++) {
        const x = nums[i];
        freq.set(x, (freq.get(x) || 0) + 1);
        if (freq.get(x) === 1) distinct++;
        windowSum += x;
        if (i >= k) {
            const y = nums[i - k];
            windowSum -= y;
            const c = freq.get(y) - 1;
            freq.set(y, c);
            if (c === 0) distinct--;
        }
        if (i >= k - 1 && distinct >= m) {
            best = Math.max(best, windowSum);
        }
    }
    return best;
};
